        public override async Task<ProfessionalTax> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<ProfessionalTax>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.State),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

