        {
            return await UOW.GetRepositoryAsync<ProfessionalTax>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.State.Name.Contains(search.Name)),
                include: i => i.Include(x => x.State),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "State.Name", ascending: !search.IsDescend);
        }
